import { request } from '../axios';

export async function netIQLogin(
  idpLoginURL: string,
  username: string,
  password: string,
) {
  const url: string = idpLoginURL + '?sid=0&sid=0&uiDestination=contentDiv';
  const headers: any = { 'Content-Type': 'application/x-www-form-urlencoded' };
  const params = new URLSearchParams();
  params.append('option', 'credentials');
  params.append('Ecom_User_ID', username);
  params.append('Ecom_Password', password);
  return request({ method: 'POST', url, headers, data: params });
}
